class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.size();
        int minPenalty = INT_MAX;
        int bestClosingTime = 0;
        for (int i = 0; i <= n; ++i) {
            int penalty = 0;
            for (int j = 0; j < i; ++j) {
                if (customers[j] == 'Y' && penalty == 0) {
                    penalty++;
                }
            }
            for (int j = i; j < n; ++j) {
                if (customers[j] == 'Y') {
                    penalty++;
                }
            }
            if (penalty < minPenalty) {
                minPenalty = penalty;
                bestClosingTime = i;
            }
        }
        return bestClosingTime;
    }
};
